Use `BehaviorSubject<number>`. It seeds with an initial value, `.getValue()` lets you read synchronously, and a new subscriber gets the current value immediately on subscribe.

```typescript
import { BehaviorSubject, Observable } from "rxjs";

const count$ = new BehaviorSubject<number>(0);

export const counter$: Observable<number> = count$.asObservable();

export function increment(): void {
  count$.next(count$.getValue() + 1);
}
```

```typescript
import { ReplaySubject, Observable } from "rxjs";

interface Activity {
  at: number;
  text: string;
}

const log$ = new ReplaySubject<Activity>(5);

export const activity$: Observable<Activity> = log$.asObservable();

export function record(a: Activity): void {
  log$.next(a);
}

// Unlike BehaviorSubject (only the latest), ReplaySubject(5) buffers the last
