```typescript
import { Observable, defer, shareReplay } from "rxjs";

interface Profile {
  id: string;
  handle: string;
}

declare function httpGetProfile(): Promise<Profile>;

export const profile$: Observable<Profile> = defer(() => httpGetProfile()).pipe(
  shareReplay({ bufferSize: 1, refCount: true })
);

// refCount:true releases the upstream subscription when the last subscriber
// unsubscribes, avoiding leaks. bufferSize:1 means late subscribers see the
// most recent response.
```

Use `share()`. It turns a cold observable into a refCounted hot one — the first subscriber triggers the upstream, and subsequent subscribers attach to the same subscription. When the last subscriber leaves, the upstream unsubscribes.

```typescript
import { interval, Observable, share, take } from "rxjs";

const ticks$: Observable<number> = interval(1000).pipe(take(5), share());

ticks$.subscribe((n: number) => void n);
ticks$.subscribe((n: number) => void n);
```

With `{ bufferSize: n, refCount: true }`, the source subscription is released when the last subscriber unsubscribes and re-created on the next new subscription. With `refCount: false` the upstream stays subscribed forever after the first subscribe — a common leak.

```typescript
import { Observable, defer, shareReplay, tap } from "rxjs";

declare function fetchSettings(): Promise<Readonly<Record<string, string>>>;

export const settings$: Observable<Readonly<Record<string, string>>> = defer(() =>
  fetchSettings()
).pipe(
  tap({ next: () => console.log("hit network") }),
  shareReplay({ bufferSize: 1, refCount: true })
);
```

