Construct a new Observable and return a teardown function from the subscribe handler. The returned function runs when the subscriber unsubscribes or when the observable completes or errors.

```typescript
import { Observable } from "rxjs";

export function everyMs$(ms: number): Observable<number> {
  return new Observable<number>((subscriber) => {
    let n = 0;
    const id = setInterval(() => subscriber.next(n++), ms);
    return () => {
      clearInterval(id);
    };
  });
}
```

Returning a teardown function is how you guarantee resource cleanup when the consumer unsubscribes, when the observable completes, or when it errors. Without it, the underlying resource (timer, socket, listener) leaks for the life of the process.

```typescript
import { Observable } from "rxjs";

interface Frame {
  bytes: Uint8Array;
}

interface SockLike {
  onMessage: (f: Frame) => void;
  close: () => void;
}

declare function openSock(url: string): SockLike;

export function frames$(url: string): Observable<Frame> {
  return new Observable<Frame>((subscriber) => {
    const sock = openSock(url);
    sock.onMessage = (f: Frame) => subscriber.next(f);
    return () => sock.close();
  });
}
```

```typescript
import { Observable } from "rxjs";

export function clickStream$(el: HTMLElement): Observable<MouseEvent> {
  return new Observable<MouseEvent>((subscriber) => {
    const handler = (ev: MouseEvent): void => subscriber.next(ev);
    el.addEventListener("click", handler);
    return () => el.removeEventListener("click", handler);
  });
}
```

```typescript
import { Observable } from "rxjs";

interface Chunk {
  bytes: Uint8Array;
}

interface StreamLike {
  read(): Promise<{ done: boolean; value?: Uint8Array }>;
  cancel(): void;
}

export function chunks$(stream: StreamLike): Observable<Chunk> {
  return new Observable<Chunk>((subscriber) => {
    let cancelled = false;
    const run = async (): Promise<void> => {
      try {
        while (!cancelled) {
          const step = await stream.read();
          if (step.done) break;
          if (step.value) subscriber.next({ bytes: step.value });
        }
        subscriber.complete();
      } catch (err: unknown) {
        subscriber.error(err);
      }
    };
    void run();
    return () => {
      cancelled = true;
      stream.cancel();
    };
  });
}
```

Fix this RxJS v7 code: the interval is never cleared on unsubscribe.

```ts
import { Observable } from "rxjs";
export const ticks$ = new Observable<number>((subscriber) => {
  let n = 0;
  setInterval(() => subscriber.next(n++), 100);
});
```

Capture the interval id, return a teardown function from the subscribe callback, and clear it there. RxJS will invoke the teardown on unsubscribe, completion, or error.

```typescript
import { Observable } from "rxjs";

export const ticks$: Observable<number> = new Observable<number>((subscriber) => {
  let n = 0;
  const id = setInterval(() => subscriber.next(n++), 100);
  return () => clearInterval(id);
});
```

