```typescript
import { from, interval, combineLatest, Observable, map, take } from "rxjs";

interface Profile {
  id: string;
  handle: string;
}

interface ViewModel {
  profile: Profile;
  tick: number;
}

declare function loadProfile(): Promise<Profile>;

export function vm$(): Observable<ViewModel> {
  const profile$: Observable<Profile> = from(loadProfile());
  const tick$: Observable<number> = interval(1000).pipe(take(5));
  return combineLatest({ profile: profile$, tick: tick$ }).pipe(
    map(({ profile, tick }) => ({ profile, tick }))
  );
}
```

Wrap the iterable with `from`, then insert a `tap({ next })` to observe without transforming.

```typescript
