interface Row {
  id: number;
}

const rows: readonly Row[] = [{ id: 1 }, { id: 2 }, { id: 3 }];

export const rowStream$: Observable<Row> = from(rows).pipe(
  tap({
    next: (r: Row) => console.log("row", r.id),
  })
